506     }
507 
508     Type *TCTy = VPTypeAnalysis(Plan).inferScalarType(Plan.getTripCount());
509     Plan.getUF().replaceAllUsesWith(Plan.getConstantInt(TCTy, UF));
510   });
511   if (UF == 1) {
512     return;
513   }
514 
515   UnrollState Unroller(Plan, UF);
516 
517   // Iterate over all blocks in the plan starting from Entry, and unroll
518   // recipes inside them. This includes the vector preheader and middle blocks,
519   // which may set up or post-process per-part values.
520   ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>> RPOT(
521       Plan.getEntry());
522   for (VPBlockBase *VPB : RPOT)
523     Unroller.unrollBlock(VPB);
524 
525   unsigned Part = 1;
526   // Remap operands of cloned header phis to update backedge values. The header
527   // phis cloned during unrolling are just after the header phi for part 0.
528   // Reset Part to 1 when reaching the first (part 0) recipe of a block.
529   for (VPRecipeBase &H :
530        Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis()) {
531     // The second operand of Fixed Order Recurrence phi's, feeding the spliced
532     // value across the backedge, needs to remap to the last part of the spliced
533     // value.
534     if (isa<VPFirstOrderRecurrencePHIRecipe>(&H)) {
535       Unroller.remapOperand(&H, 1, UF - 1);
536       continue;
537     }
538     if (Unroller.contains(H.getVPSingleValue())) {
539       Part = 1;
540       continue;
541     }
542     Unroller.remapOperands(&H, Part);
543     Part++;
544   }
545 
546   VPlanTransforms::removeDeadRecipes(Plan);
547 }
