1436 /// Given a first argmin/argmax pattern with strict predicate consisting of
1437 /// 1) a MinOrMax reduction \p MinOrMaxPhiR producing \p MinOrMaxResult,
1438 /// 2) a wide induction \p WideIV,
1439 /// 3) a FindLastIV reduction \p FindLastIVPhiR using \p WideIV,
1440 /// return the smallest index of the FindLastIV reduction result using UMin,
1441 /// unless \p MinOrMaxResult equals the start value of its MinOrMax reduction.
1442 /// In that case, return the start value of the FindLastIV reduction instead.
1443 /// If \p WideIV is not canonical, a new canonical wide IV is added, and the
1444 /// final result is scaled back to the non-canonical \p WideIV.
1445 /// The final value of the FindLastIV reduction is originally computed using
1446 /// \p FindIVSelect, \p FindIVCmp, and \p FindIVRdxResult, which are replaced
1447 /// and removed.
1448 /// Returns true if the pattern was handled successfully, false otherwise.
1449 static bool handleFirstArgMinOrMax(
1450     VPlan &Plan, VPReductionPHIRecipe *MinOrMaxPhiR,
1451     VPReductionPHIRecipe *FindLastIVPhiR, VPWidenIntOrFpInductionRecipe *WideIV,
1452     VPInstruction *MinOrMaxResult, VPInstruction *FindIVSelect,
1453     VPRecipeBase *FindIVCmp, VPInstruction *FindIVRdxResult) {
1454   assert(!FindLastIVPhiR->isInLoop() && !FindLastIVPhiR->isOrdered() &&
1455          "inloop and ordered reductions not supported");
1456   assert(FindLastIVPhiR->getVFScaleFactor() == 1 &&
1457          "FindIV reduction must not be scaled");
1458 
1459   Type *Ty = Plan.getVectorLoopRegion()->getCanonicalIVType();
1460   // TODO: Support non (i.e., narrower than) canonical IV types.
1461   // TODO: Emit remarks for failed transformations.
1462   if (Ty != VPTypeAnalysis(Plan).inferScalarType(WideIV))
1463     return false;
1464 
1465   auto *FindIVSelectR = cast<VPSingleDefRecipe>(
1466       FindLastIVPhiR->getBackedgeValue()->getDefiningRecipe());
1467   assert(
1468       match(FindIVSelectR, m_Select(m_VPValue(), m_VPValue(), m_VPValue())) &&
1469       "backedge value must be a select");
1470   if (FindIVSelectR->getOperand(1) != WideIV &&
1471       FindIVSelectR->getOperand(2) != WideIV)
1472     return false;
1473 
1474   // If the original wide IV is not canonical, create a new one. The canonical
1475   // wide IV is guaranteed to not wrap for all lanes that are active in the
1476   // vector loop.
1477   if (!WideIV->isCanonical()) {
1478     VPIRValue *Zero = Plan.getConstantInt(Ty, 0);
1479     VPIRValue *One = Plan.getConstantInt(Ty, 1);
1480     auto *WidenCanIV = new VPWidenIntOrFpInductionRecipe(
1481         nullptr, Zero, One, WideIV->getVFValue(),
1482         WideIV->getInductionDescriptor(),
1483         VPIRFlags::WrapFlagsTy(/*HasNUW=*/true, /*HasNSW=*/false),
1484         WideIV->getDebugLoc());
1485     WidenCanIV->insertBefore(WideIV);
1486 
1487     // Update the select to use the wide canonical IV.
1488     FindIVSelectR->setOperand(FindIVSelectR->getOperand(1) == WideIV ? 1 : 2,
1489                               WidenCanIV);
1490   }
1491   FindLastIVPhiR->setOperand(0, Plan.getOrAddLiveIn(PoisonValue::get(Ty)));
