1506   //
1507   // For example, we transforms two independent reduction result computations
1508   // for
1509   //
1510   // <x1> vector loop: {
1511   //  vector.body:
1512   //    ...
1513   //    ir<%iv> = WIDEN-INDUCTION nuw nsw ir<10>, ir<1>, vp<%0>
1514   //    WIDEN-REDUCTION-PHI ir<%min.idx> = phi ir<sentinel.min.start>,
1515   //                                           ir<%min.idx.next>
1516   //    WIDEN-REDUCTION-PHI ir<%min.val> = phi ir<100>, ir<%min.val.next>
1517   //    ....
1518   //    WIDEN-INTRINSIC ir<%min.val.next> = call llvm.umin(ir<%min.val>, ir<%l>)
1519   //    WIDEN ir<%min.idx.next> = select ir<%cmp>, ir<%iv>, ir<%min.idx>
1520   //    ...
1521   // }
1522   // Successor(s): middle.block
1523   //
1524   // middle.block:
1525   //  vp<%iv.rdx> = compute-reduction-result (smax) vp<%min.idx.next>
1526   //  vp<%min.result> = compute-reduction-result (umin) ir<%min.val.next>
1527   //  vp<%cmp> = icmp ne vp<%iv.rdx>, ir<sentinel.min.start>
1528   //  vp<%find.iv.result> = select vp<%cmp>, vp<%iv.rdx>, ir<10>
