400 void UnrollState::unrollBlock(VPBlockBase *VPB) {
401   auto *VPR = dyn_cast<VPRegionBlock>(VPB);
402   if (VPR) {
403     if (VPR->isReplicator())
404       return unrollReplicateRegionByUF(VPR);
405 
406     // Traverse blocks in region in RPO to ensure defs are visited before uses
407     // across blocks.
408     ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>>
409         RPOT(VPR->getEntry());
410     for (VPBlockBase *VPB : RPOT)
411       unrollBlock(VPB);
412     return;
413   }
414 
415   // VPB is a VPBasicBlock; unroll it, i.e., unroll its recipes.
416   auto *VPBB = cast<VPBasicBlock>(VPB);
417   auto InsertPtForPhi = VPBB->getFirstNonPhi();
418   for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
419     if (ToSkip.contains(&R) || isa<VPIRInstruction>(&R))
420       continue;
421 
422     // Add all VPValues for all parts to AnyOf, FirstActiveLaneMask and
423     // Compute*Result which combine all parts to compute the final value.
424     VPValue *Op1;
425     if (match(&R, m_VPInstruction<VPInstruction::AnyOf>(m_VPValue(Op1))) ||
426         match(&R, m_FirstActiveLane(m_VPValue(Op1))) ||
427         match(&R, m_LastActiveLane(m_VPValue(Op1))) ||
428         match(&R,
429               m_ComputeAnyOfResult(m_VPValue(), m_VPValue(), m_VPValue(Op1))) ||
430         match(&R, m_ComputeReductionResult(m_VPValue(Op1)))) {
431       addUniformForAllParts(cast<VPInstruction>(&R));
432       for (unsigned Part = 1; Part != UF; ++Part)
433         R.addOperand(getValueForPart(Op1, Part));
434       continue;
435     }
436     VPValue *Op0;
437     if (match(&R, m_ExtractLane(m_VPValue(Op0), m_VPValue(Op1)))) {
438       addUniformForAllParts(cast<VPInstruction>(&R));
439       for (unsigned Part = 1; Part != UF; ++Part)
440         R.addOperand(getValueForPart(Op1, Part));
441       continue;
442     }
443 
444     VPValue *Op2;
445     if (match(&R, m_ExtractLastActive(m_VPValue(), m_VPValue(Op1),
446                                       m_VPValue(Op2)))) {
447       addUniformForAllParts(cast<VPInstruction>(&R));
448       for (unsigned Part = 1; Part != UF; ++Part) {
449         R.addOperand(getValueForPart(Op1, Part));
450         R.addOperand(getValueForPart(Op2, Part));
451       }
452       continue;
453     }
454 
455     if (Plan.hasScalarVFOnly()) {
456       if (match(&R, m_ExtractLastPart(m_VPValue(Op0))) ||
457           match(&R, m_ExtractPenultimateElement(m_VPValue(Op0)))) {
458         auto *I = cast<VPInstruction>(&R);
459         bool IsPenultimatePart =
460             I->getOpcode() == VPInstruction::ExtractPenultimateElement;
461         unsigned PartIdx = IsPenultimatePart ? UF - 2 : UF - 1;
462         // For scalar VF, directly use the scalar part value.
463         I->replaceAllUsesWith(getValueForPart(Op0, PartIdx));
464         continue;
465       }
466     }
467     // For vector VF, the penultimate element is always extracted from the last part.
468     if (match(&R, m_ExtractLastLaneOfLastPart(m_VPValue(Op0))) ||
469         match(&R, m_ExtractPenultimateElement(m_VPValue(Op0)))) {
470       addUniformForAllParts(cast<VPSingleDefRecipe>(&R));
471       R.setOperand(0, getValueForPart(Op0, UF - 1));
472       continue;
473     }
474 
475     auto *SingleDef = dyn_cast<VPSingleDefRecipe>(&R);
476     if (SingleDef && vputils::isUniformAcrossVFsAndUFs(SingleDef)) {
477       addUniformForAllParts(SingleDef);
478       continue;
479     }
480 
481     if (auto *H = dyn_cast<VPHeaderPHIRecipe>(&R)) {
482       unrollHeaderPHIByUF(H, InsertPtForPhi);
483       continue;
484     }
485 
486     unrollRecipeByUF(R);
487   }
488 }
