3702 static void
3703 expandVPWidenIntOrFpInduction(VPWidenIntOrFpInductionRecipe *WidenIVR,
3704                               VPTypeAnalysis &TypeInfo) {
3705   VPlan *Plan = WidenIVR->getParent()->getPlan();
3706   VPValue *Start = WidenIVR->getStartValue();
3707   VPValue *Step = WidenIVR->getStepValue();
3708   VPValue *VF = WidenIVR->getVFValue();
3709   DebugLoc DL = WidenIVR->getDebugLoc();
3710 
3711   // The value from the original loop to which we are mapping the new induction
3712   // variable.
3713   Type *Ty = TypeInfo.inferScalarType(WidenIVR);
3714 
3715   const InductionDescriptor &ID = WidenIVR->getInductionDescriptor();
3716   Instruction::BinaryOps AddOp;
3717   Instruction::BinaryOps MulOp;
3718   VPIRFlags Flags = *WidenIVR;
3719   if (ID.getKind() == InductionDescriptor::IK_IntInduction) {
3720     AddOp = Instruction::Add;
3721     MulOp = Instruction::Mul;
3722   } else {
3723     AddOp = ID.getInductionOpcode();
3724     MulOp = Instruction::FMul;
3725   }
3726 
3727   // If the phi is truncated, truncate the start and step values.
3728   VPBuilder Builder(Plan->getVectorPreheader());
3729   Type *StepTy = TypeInfo.inferScalarType(Step);
3730   if (Ty->getScalarSizeInBits() < StepTy->getScalarSizeInBits()) {
3731     assert(StepTy->isIntegerTy() && "Truncation requires an integer type");
3732     Step = Builder.createScalarCast(Instruction::Trunc, Step, Ty, DL);
3733     Start = Builder.createScalarCast(Instruction::Trunc, Start, Ty, DL);
3734     // Truncation doesn't preserve WrapFlags.
3735     Flags.dropPoisonGeneratingFlags();
3736     StepTy = Ty;
3737   }
3738 
3739   // Construct the initial value of the vector IV in the vector loop preheader.
3740   Type *IVIntTy =
3741       IntegerType::get(Plan->getContext(), StepTy->getScalarSizeInBits());
3742   VPValue *Init = Builder.createNaryOp(VPInstruction::StepVector, {}, IVIntTy);
3743   if (StepTy->isFloatingPointTy())
3744     Init = Builder.createWidenCast(Instruction::UIToFP, Init, StepTy);
3745 
3746   VPValue *SplatStart = Builder.createNaryOp(VPInstruction::Broadcast, Start);
3747   VPValue *SplatStep = Builder.createNaryOp(VPInstruction::Broadcast, Step);
3748 
3749   Init = Builder.createNaryOp(MulOp, {Init, SplatStep}, Flags);
3750   Init = Builder.createNaryOp(AddOp, {SplatStart, Init}, Flags,
3751                               DebugLoc::getUnknown(), "induction");
3752 
3753   // Create the widened phi of the vector IV.
3754   auto *WidePHI = new VPWidenPHIRecipe(WidenIVR->getPHINode(), Init,
3755                                        WidenIVR->getDebugLoc(), "vec.ind");
3756   WidePHI->insertBefore(WidenIVR);
3757 
3758   // Create the backedge value for the vector IV.
3759   VPValue *Inc;
3760   VPValue *Prev;
3761   // If unrolled, use the increment and prev value from the operands.
3762   if (auto *SplatVF = WidenIVR->getSplatVFValue()) {
3763     Inc = SplatVF;
3764     Prev = WidenIVR->getLastUnrolledPartOperand();
3765   } else {
3766     if (VPRecipeBase *R = VF->getDefiningRecipe())
3767       Builder.setInsertPoint(R->getParent(), std::next(R->getIterator()));
3768     // Multiply the vectorization factor by the step using integer or
3769     // floating-point arithmetic as appropriate.
3770     if (StepTy->isFloatingPointTy())
3771       VF = Builder.createScalarCast(Instruction::CastOps::UIToFP, VF, StepTy,
3772                                     DL);
3773     else
3774       VF = Builder.createScalarZExtOrTrunc(VF, StepTy,
3775                                            TypeInfo.inferScalarType(VF), DL);
3776 
3777     Inc = Builder.createNaryOp(MulOp, {Step, VF}, Flags);
3778     Inc = Builder.createNaryOp(VPInstruction::Broadcast, Inc);
3779     Prev = WidePHI;
3780   }
3781 
3782   VPBasicBlock *ExitingBB = Plan->getVectorLoopRegion()->getExitingBasicBlock();
3783   Builder.setInsertPoint(ExitingBB, ExitingBB->getTerminator()->getIterator());
3784   auto *Next = Builder.createNaryOp(AddOp, {Prev, Inc}, Flags,
3785                                     WidenIVR->getDebugLoc(), "vec.ind.next");
3786 
3787   WidePHI->addOperand(Next);
3788 
3789   WidenIVR->replaceAllUsesWith(WidePHI);
3790 }
