3792 /// Expand a VPWidenPointerInductionRecipe into executable recipes, for the
3793 /// initial value, phi and backedge value. In the following example:
3794 ///
3795 ///  <x1> vector loop: {
3796 ///    vector.body:
3797 ///      EMIT ir<%ptr.iv> = WIDEN-POINTER-INDUCTION %start, %step, %vf
3798 ///      ...
3799 ///      EMIT branch-on-count ...
3800 ///  }
3801 ///
3802 /// WIDEN-POINTER-INDUCTION will get expanded to:
3803 ///
3804 ///  <x1> vector loop: {
3805 ///    vector.body:
3806 ///      EMIT-SCALAR %pointer.phi = phi %start, %ptr.ind
3807 ///      EMIT %mul = mul %stepvector, %step
3808 ///      EMIT %vector.gep = wide-ptradd %pointer.phi, %mul
3809 ///      ...
3810 ///      EMIT %ptr.ind = ptradd %pointer.phi, %vf
3811 ///      EMIT branch-on-count ...
3812 ///  }
3813 static void expandVPWidenPointerInduction(VPWidenPointerInductionRecipe *R,
3814                                           VPTypeAnalysis &TypeInfo) {
3815   VPlan *Plan = R->getParent()->getPlan();
3816   VPValue *Start = R->getStartValue();
3817   VPValue *Step = R->getStepValue();
3818   VPValue *VF = R->getVFValue();
3819 
3820   assert(R->getInductionDescriptor().getKind() ==
3821              InductionDescriptor::IK_PtrInduction &&
3822          "Not a pointer induction according to InductionDescriptor!");
3823   assert(TypeInfo.inferScalarType(R)->isPointerTy() && "Unexpected type.");
3824   assert(!R->onlyScalarsGenerated(Plan->hasScalableVF()) &&
3825          "Recipe should have been replaced");
3826 
3827   VPBuilder Builder(R);
3828   DebugLoc DL = R->getDebugLoc();
3829 
3830   // Build a scalar pointer phi.
3831   VPPhi *ScalarPtrPhi = Builder.createScalarPhi(Start, DL, "pointer.phi");
3832 
3833   // Create actual address geps that use the pointer phi as base and a
3834   // vectorized version of the step value (<step*0, ..., step*N>) as offset.
3835   Builder.setInsertPoint(R->getParent(), R->getParent()->getFirstNonPhi());
3836   Type *StepTy = TypeInfo.inferScalarType(Step);
3837   VPValue *Offset = Builder.createNaryOp(VPInstruction::StepVector, {}, StepTy);
3838   Offset = Builder.createOverflowingOp(Instruction::Mul, {Offset, Step});
3839   VPValue *PtrAdd =
3840       Builder.createWidePtrAdd(ScalarPtrPhi, Offset, DL, "vector.gep");
3841   R->replaceAllUsesWith(PtrAdd);
3842 
3843   // Create the backedge value for the scalar pointer phi.
3844   VPBasicBlock *ExitingBB = Plan->getVectorLoopRegion()->getExitingBasicBlock();
3845   Builder.setInsertPoint(ExitingBB, ExitingBB->getTerminator()->getIterator());
3846   VF = Builder.createScalarZExtOrTrunc(VF, StepTy, TypeInfo.inferScalarType(VF),
3847                                        DL);
3848   VPValue *Inc = Builder.createOverflowingOp(Instruction::Mul, {Step, VF});
3849 
3850   VPValue *InductionGEP =
3851       Builder.createPtrAdd(ScalarPtrPhi, Inc, DL, "ptr.ind");
3852   ScalarPtrPhi->addOperand(InductionGEP);
3853 }
