3855 void VPlanTransforms::dissolveLoopRegions(VPlan &Plan) {
3856   // Replace loop regions with explicity CFG.
3857   SmallVector<VPRegionBlock *> LoopRegions;
3858   for (VPRegionBlock *R : VPBlockUtils::blocksOnly<VPRegionBlock>(
3859            vp_depth_first_deep(Plan.getEntry()))) {
3860     if (!R->isReplicator())
3861       LoopRegions.push_back(R);
