3867 void VPlanTransforms::expandBranchOnTwoConds(VPlan &Plan) {
3868   SmallVector<VPInstruction *> WorkList;
3869   // The transform runs after dissolving loop regions, so all VPBasicBlocks
3870   // terminated with BranchOnTwoConds are reached via a shallow traversal.
3871   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
3872            vp_depth_first_shallow(Plan.getEntry()))) {
3873     if (!VPBB->empty() && match(&VPBB->back(), m_BranchOnTwoConds()))
3874       WorkList.push_back(cast<VPInstruction>(&VPBB->back()));
3875   }
3876 
3877   // Expand BranchOnTwoConds instructions into explicit CFG with two new
3878   // single-condition branches:
3879   // 1. A branch that replaces BranchOnTwoConds, jumps to the first successor if
3880   //    the first condition is true, and otherwise jumps to a new interim block.
3881   // 2. A branch that ends the interim block, jumps to the second successor if
3882   //    the second condition is true, and otherwise jumps to the third
3883   //    successor.
3884   for (VPInstruction *Br : WorkList) {
3885     assert(Br->getNumOperands() == 2 &&
3886            "BranchOnTwoConds must have exactly 2 conditions");
3887     DebugLoc DL = Br->getDebugLoc();
3888     VPBasicBlock *BrOnTwoCondsBB = Br->getParent();
3889     const auto Successors = to_vector(BrOnTwoCondsBB->getSuccessors());
3890     assert(Successors.size() == 3 &&
3891            "BranchOnTwoConds must have exactly 3 successors");
3892 
3893     for (VPBlockBase *Succ : Successors)
3894       VPBlockUtils::disconnectBlocks(BrOnTwoCondsBB, Succ);
3895 
3896     VPValue *Cond0 = Br->getOperand(0);
3897     VPValue *Cond1 = Br->getOperand(1);
3898     VPBlockBase *Succ0 = Successors[0];
3899     VPBlockBase *Succ1 = Successors[1];
3900     VPBlockBase *Succ2 = Successors[2];
3901     assert(!Succ0->getParent() && !Succ1->getParent() && !Succ2->getParent() &&
3902            !BrOnTwoCondsBB->getParent() && "regions must already be dissolved");
3903 
3904     VPBasicBlock *InterimBB =
3905         Plan.createVPBasicBlock(BrOnTwoCondsBB->getName() + ".interim");
3906 
3907     VPBuilder(BrOnTwoCondsBB)
3908         .createNaryOp(VPInstruction::BranchOnCond, {Cond0}, DL);
3909     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, Succ0);
3910     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, InterimBB);
3911 
3912     VPBuilder(InterimBB).createNaryOp(VPInstruction::BranchOnCond, {Cond1}, DL);
3913     VPBlockUtils::connectBlocks(InterimBB, Succ1);
3914     VPBlockUtils::connectBlocks(InterimBB, Succ2);
3915     Br->eraseFromParent();
3916   }
3917 }
